func structToMap(s any) map[string]any {
	m := make(map[string]any)
	t := reflect.TypeOf(s)

	for i := 0; i < t.NumMethod(); i++ {
		method := t.Method(i)
		if method.PkgPath != "" {
			continue
		}
		if method.Type.NumIn() == 1 {
			m[method.Name] = ""
		}
	}

	for i := 0; i < t.NumField(); i++ {
		field := t.Field(i)
		if field.PkgPath != "" {
			continue
		}
		m[field.Name] = ""
	}
	return m
}
